mapper.select:
SELECT monitor_date AS monitorDate, SUM(flow_rate) AS totalFlow, AVG(flow_rate) AS avgFlow, AVG(water_pressure) AS avgPressure FROM pipe_flow_record WHERE monitor_date BETWEEN #{startDate} AND #{endDate}
AND pipe_no = #{pipeNo}
GROUP BY monitor_date ORDER BY monitor_date

SELECT * FROM pipe_flow_record
ORDER BY monitor_date DESC, monitor_hour DESC
LIMIT #{limit}

SELECT monitor_date AS monitorDate, monitor_hour AS monitorHour,
       flow_rate AS flowRate
FROM pipe_flow_record
WHERE pipe_no = #{pipeNo}
ORDER BY monitor_date DESC, monitor_hour DESC
LIMIT #{limit}

SELECT pipe_no AS pipeNo, pipe_name AS pipeName, SUM(flow_rate) AS totalFlow, AVG(flow_rate) AS avgFlow FROM pipe_flow_record WHERE monitor_date BETWEEN #{startDate} AND #{endDate} AND pipe_no IN
#{pn}
GROUP BY pipe_no, pipe_name ORDER BY totalFlow DESC

SELECT monitor_date AS monitorDate, SUM(total_flow) AS totalFlow, AVG(avg_flow) AS avgFlow, AVG(avg_pressure) AS avgPressure FROM daily_flow_summary WHERE monitor_date BETWEEN #{startDate} AND #{endDate}
AND pipe_no = #{pipeNo}
GROUP BY monitor_date ORDER BY monitor_date

SELECT 0 AS anomalyLevel, SUM(anomaly_0) AS count FROM daily_flow_summary
WHERE monitor_date BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 1, SUM(anomaly_1) FROM daily_flow_summary
WHERE monitor_date BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 2, SUM(anomaly_2) FROM daily_flow_summary
WHERE monitor_date BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 3, SUM(anomaly_3) FROM daily_flow_summary
WHERE monitor_date BETWEEN #{startDate} AND #{endDate}

SELECT monitor_hour AS monitorHour, AVG(avg_flow) AS avgFlow, MAX(max_flow) AS maxFlow FROM hourly_flow_summary WHERE pipe_no IN
#{pn}
GROUP BY monitor_hour ORDER BY monitor_hour

SELECT pipe_no AS pipeNo, SUM(total_flow) AS totalFlow, AVG(avg_flow) AS avgFlow FROM daily_flow_summary WHERE monitor_date BETWEEN #{startDate} AND #{endDate} AND pipe_no IN
#{pn}
GROUP BY pipe_no ORDER BY totalFlow DESC
